public class Q1 {
    abstract static class Vehicle {
        String make; int year; double fuelLevel = 100;
        Vehicle(String make, int year) { this.make=make; this.year=year; }
        void refuel(double amt) { fuelLevel = Math.min(100, fuelLevel + amt); }
        String getStatus() { return make+"("+year+") fuel="+String.format("%.1f",fuelLevel)+"%"; }
        abstract void drive(int km);
    }
    static class Car   extends Vehicle {
        Car(String m, int y) { super(m,y); }
        @Override void drive(int km) { fuelLevel -= km * 0.08; }
    }
    static class Truck extends Vehicle {
        Truck(String m, int y) { super(m,y); }
        @Override void drive(int km) { fuelLevel -= km * 0.15; }
    }

    public static void main(String[] args) {
        Vehicle c = new Car("Toyota", 2020);
        Vehicle t = new Truck("Volvo", 2019);
        c.drive(200); System.out.println(c.getStatus()); // fuel=84.0%
        t.drive(200); System.out.println(t.getStatus()); // fuel=70.0%
        c.refuel(50); System.out.println(c.getStatus()); // fuel=100.0% (capped)
    }
}

