public class Q4 {
    interface MathUtils {
        static int clamp(int v, int min, int max) {
            return Math.max(min, Math.min(max, v));
        }
        static double lerp(double a, double b, double t) {
            return a + (b - a) * t;
        }
    }

    public static void main(String[] args) {
        System.out.println(MathUtils.clamp(15, 0, 10));       // 10
        System.out.println(MathUtils.clamp(-5, 0, 10));       // 0
        System.out.println(MathUtils.clamp(5,  0, 10));       // 5
        System.out.println(MathUtils.lerp(0.0, 10.0, 0.5));   // 5.0
        System.out.println(MathUtils.lerp(0.0, 100.0, 0.25)); // 25.0
    }
}

