import java.util.*;

public class Q7 {
    static class Employee implements Comparable<Employee> {
        String name; double salary; String dept;
        Employee(String n, double s, String d) { name=n; salary=s; dept=d; }
        @Override public int compareTo(Employee o) {
            return Double.compare(o.salary, this.salary); // descending
        }
        public String toString() { return name+"($"+salary+")"; }
    }

    public static void main(String[] args) {
        List<Employee> staff = new ArrayList<>(List.of(
            new Employee("Alice", 75000, "Eng"),
            new Employee("Bob",   95000, "Mgmt"),
            new Employee("Carol", 60000, "HR")
        ));
        Collections.sort(staff);
        System.out.println(staff); // [Bob($95000.0), Alice($75000.0), Carol($60000.0)]

        staff.sort(Comparator.comparing(e -> e.name));
        System.out.println(staff); // [Alice($75000.0), Bob($95000.0), Carol($60000.0)]
    }
}

