import java.util.*;

public class Q15 {
    abstract static class AbstractIterator<T> implements Iterator<T> {
        @Override public boolean hasNext() { return currentIndex() < totalSize(); }
        @Override public T next() {
            if (!hasNext()) throw new NoSuchElementException();
            return getElement(advanceAndGet());
        }
        protected abstract int totalSize();
        protected abstract int currentIndex();
        protected abstract int advanceAndGet();
        protected abstract T getElement(int index);
    }

    static class ArrayIterator<T> extends AbstractIterator<T> {
        T[] data; int idx = 0;
        @SuppressWarnings("unchecked")
        ArrayIterator(T[] data) { this.data = data; }
        @Override protected int totalSize()     { return data.length; }
        @Override protected int currentIndex()  { return idx; }
        @Override protected int advanceAndGet() { return idx++; }
        @Override protected T   getElement(int i){ return data[i]; }
    }

    static class RangeIterator extends AbstractIterator<Integer> {
        int current; int end;
        RangeIterator(int start, int end) { this.current=start; this.end=end; }
        @Override protected int     totalSize()    { return end - current + (current <= end ? 1 : 0); }
        @Override protected int     currentIndex() { return current <= end ? 0 : 1; }
        @Override protected boolean hasNext()       { return current <= end; }
        @Override protected int     advanceAndGet() { return current++; }
        @Override protected Integer getElement(int i){ return i; } // i is the value itself
    }

    public static void main(String[] args) {
        Iterator<String>  ai = new ArrayIterator<>(new String[]{"a","b","c"});
        while (ai.hasNext()) System.out.print(ai.next() + " ");
        System.out.println();
        Iterator<Integer> ri = new RangeIterator(1, 5);
        while (ri.hasNext()) System.out.print(ri.next() + " ");
        System.out.println();
    }
}

