public class Q16 {
    interface A { default String hello() { return "Hello from A"; } }
    interface B { default String hello() { return "Hello from B"; } }
    interface C extends A, B {} // C does not resolve — Impl must

    static class Impl implements C {
        @Override public String hello() {
            // Use both: explicitly call each parent's default
            return A.super.hello() + " and " + B.super.hello();
        }
    }

    static class ImplPreferA implements C {
        @Override public String hello() { return A.super.hello(); }
    }

    public static void main(String[] args) {
        System.out.println(new Impl().hello());     // Hello from A and Hello from B
        System.out.println(new ImplPreferA().hello()); // Hello from A
    }
}

