import java.util.*;

public class Q19 {
    abstract static class FileSystemEntry {
        String name;
        FileSystemEntry(String name) { this.name = name; }
        abstract long size();
        abstract void print(String indent);
    }

    static class File extends FileSystemEntry {
        long bytes;
        File(String name, long bytes) { super(name); this.bytes=bytes; }
        @Override public long size() { return bytes; }
        @Override public void print(String indent) {
            System.out.printf("%s%s (%d bytes)%n", indent, name, bytes);
        }
    }

    static class Directory extends FileSystemEntry {
        List<FileSystemEntry> children = new ArrayList<>();
        Directory(String name, FileSystemEntry... entries) {
            super(name); Collections.addAll(children, entries);
        }
        @Override public long size() { return children.stream().mapToLong(FileSystemEntry::size).sum(); }
        @Override public void print(String indent) {
            System.out.printf("%s%s/ (%d bytes)%n", indent, name, size());
            for (FileSystemEntry e : children) e.print(indent + "  ");
        }
    }

    public static void main(String[] args) {
        FileSystemEntry root = new Directory("root",
            new File("readme.txt", 1024),
            new Directory("src", new File("Main.java", 4096), new File("Utils.java", 2048)),
            new File("pom.xml", 512)
        );
        root.print("");
    }
